#include <stdio.h>
#include <math.h>
#include <stdbool.h>

static bool is_palindrome(long long n, long long base) {
    long long digits[64];
    int len = 0;
    while (n > 0) {
        digits[len++] = n % base;
        n /= base;
    }
    for (int i = 0; i < len / 2; ++i) {
        if (digits[i] != digits[len - 1 - i]) return false;
    }
    return true;
}

int main(void) {
    int t;
    if (scanf("%d", &t) != 1) return 0;
    while (t--) {
        long long N;
        scanf("%lld", &N);
        if (N == 1) { printf("2\n"); continue; }
        if (N == 2) { printf("3\n"); continue; }
        long long limit = (long long) sqrt((double) N);
        long long answer = -1;
        for (long long b = 2; b <= limit; ++b) {
            if (is_palindrome(N, b)) { answer = b; break; }
        }
        if (answer == -1) answer = N - 1; // length‑2 palindrome "11"
        printf("%lld\n", answer);
    }
    return 0;
}

