#include <bits/stdc++.h>
using namespace std;

bool isPalindrome(long long n, long long base) {
    vector<int> d;
    while (n) { d.push_back(n % base); n /= base; }
    for (size_t i = 0; i < d.size() / 2; ++i)
        if (d[i] != d[d.size() - 1 - i]) return false;
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t; if(!(cin >> t)) return 0;
    while (t--) {
        long long N; cin >> N;
        if (N == 1) { cout << 2 << '\n'; continue; }
        if (N == 2) { cout << 3 << '\n'; continue; }
        long long limit = sqrt((long double)N);
        long long ans = -1;
        for (long long b = 2; b <= limit; ++b) {
            if (isPalindrome(N, b)) { ans = b; break; }
        }
        if (ans == -1) ans = N - 1; // "11" in base N-1
        cout << ans << '\n';
    }
    return 0;
}

