import java.io.*;
import java.util.*;

public class Main {
    private static boolean isPalindrome(long n, long base) {
        long[] digits = new long[64];
        int len = 0;
        while (n > 0) {
            digits[len++] = n % base;
            n /= base;
        }
        for (int i = 0; i < len / 2; i++) {
            if (digits[i] != digits[len - 1 - i]) return false;
        }
        return true;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int t = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int caseIdx = 0; caseIdx < t; ++caseIdx) {
            long N = Long.parseLong(br.readLine().trim());
            if (N == 1) { sb.append(2).append('\n'); continue; }
            if (N == 2) { sb.append(3).append('\n'); continue; }
            long limit = (long)Math.sqrt(N);
            long ans = -1;
            for (long b = 2; b <= limit; ++b) {
                if (isPalindrome(N, b)) { ans = b; break; }
            }
            if (ans == -1) ans = N - 1; // "11"
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys, math

def is_pal(n, base):
    digits = []
    while n:
        digits.append(n % base)
        n //= base
    return digits == digits[::-1]

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        N = int(data[idx]); idx += 1
        if N == 1:
            out.append('2')
            continue
        if N == 2:
            out.append('3')
            continue
        limit = int(math.isqrt(N))
        ans = None
        for b in range(2, limit + 1):
            if is_pal(N, b):
                ans = b
                break
        if ans is None:
            ans = N - 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

